class Solution:
    def maximumScore(self, nums, multipliers):
        n = len(nums)
        m = len(multipliers)
        memo = {}
        def solve(i, left):
            if i == m:
                return 0
            key = (i, left)
            if key in memo:
                return memo[key]
            right = n - 1 - (i - left)
            best = max(multipliers[i] * nums[left] + solve(i + 1, left + 1),
                       multipliers[i] * nums[right] + solve(i + 1, left))
            memo[key] = best
            return best
        return solve(0, 0)

